import * as React from 'react';

import { interpolateRainbow } from 'd3-scale-chromatic';

import { localPoint } from '@visx/event';
import genPhyllotaxis, {
  GenPhyllotaxisFunction,
  PhyllotaxisPoint,
} from '@visx/mock-data/lib/generators/genPhyllotaxis';
import { ParentSize } from '@visx/responsive';
import { scaleLinear } from '@visx/scale';
import { Zoom } from '@visx/zoom';

export type Props = {
  width: number;
  height: number;
};

const points = [...new Array(1000)];
const colorScale = scaleLinear<number>({ range: [0, 1], domain: [0, 1000] });
const sizeScale = scaleLinear<number>({ domain: [0, 600], range: [0.5, 8] });

const Content = React.memo((props: Props) => {
  const { width, height } = props;
  // const [showMiniMap, setShowMiniMap] = React.useState<boolean>(true);
  const generator: GenPhyllotaxisFunction = genPhyllotaxis({
    radius: 10,
    width,
    height,
  });
  const phyllotaxis: PhyllotaxisPoint[] = points.map((_, i) => generator(i));

  return (
    <>
      <Zoom<SVGSVGElement> width={width} height={height}>
        {(zoom) => (
          <div style={{ position: 'relative' }}>
            <svg
              ref={zoom.containerRef}
              width={width}
              height={height}
              style={{
                cursor: zoom.isDragging ? 'grabbing' : 'grab',
                touchAction: 'none',
              }}
              onDoubleClick={(evt) => {
                const point = localPoint(evt) || { x: 0, y: 0 };
                zoom.scale({ scaleX: 2, scaleY: 2, point });
              }}
            >
              <g transform={zoom.toString()}>
                {phyllotaxis.map(({ x, y }, i) => (
                  <React.Fragment key={`dot-${i}`}>
                    <circle
                      cx={x}
                      cy={y}
                      r={i > 500 ? sizeScale(1000 - i) : sizeScale(i)}
                      fill={interpolateRainbow(colorScale(i) ?? 0)}
                    />
                  </React.Fragment>
                ))}
              </g>
            </svg>
          </div>
        )}
      </Zoom>
    </>
  );
});

const ZoomExample = React.memo(() => (
  <ParentSize debounceTime={300} enableDebounceLeadingCall={false}>
    {({ width }) => <Content width={width} height={300} />}
  </ParentSize>
));

export default ZoomExample;
